package com.fifers.leathercalculator;
import android.app.Activity;import android.content.Intent;import android.os.Bundle;import android.widget.Button; public class HomeActivity extends Activity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_home);findViewById(R.id.btnArchive).setOnClickListener(v->startActivity(new Intent(this,MainActivity.class)));findViewById(R.id.btnDifference).setOnClickListener(v->startActivity(new Intent(this,MainActivity.class)));findViewById(R.id.btnReports).setOnClickListener(v->startActivity(new Intent(this,MonthlyResultsActivity.class)));}}